    for (let i = 0; i < eff.cleanups.length; i++) {
      try { eff.cleanups[i]() } catch (e) { console.error(e) }
    }
    eff.cleanups = []
    const prev = currentEffect
    currentEffect = eff
    try { eff.fn() } finally { currentEffect = prev }
