/* ════ ui/data/list.js ════ */
// EF.ui.list — virtualized fixed-row list.
//
// opts:
//   items     : signal<any[]>            row data (signal so updates auto-render)
//   rowHeight : number                   pixels per row
//   render    : (item, index) => HTMLElement       row factory (called on demand)
