/* ════ ui/overlay/alert.js ════ */
// EF.ui.alert — inline alert/banner (not a modal).
//
// opts: {
//   kind?: 'info'|'success'|'warn'|'error' | signal,
//   title?: string|signal,
//   message?: string|signal,
//   onClose?,
// }
;(function (EF) {
  'use strict'
  const ui = EF.ui = EF.ui || {}

  const ICONS = { info: 'ⓘ', success: '✓', warn: '⚠', error: '⨯' }

  ui.alert = function (opts) {
    const o = opts || {}
    const kind    = ui.asSig(o.kind    != null ? o.kind    : 'info')
    const title   = ui.asSig(o.title   != null ? o.title   : '')
    const message = ui.asSig(o.message != null ? o.message : '')
    const el = ui.h('div', 'ef-ui-alert')
    ui.bindClass(el, kind, 'ef-ui-alert-')
    ui.bind(el, kind, function (v) {
      const assertive = v === 'error' || v === 'warn'
      el.setAttribute('role',       assertive ? 'alert'     : 'status')
      el.setAttribute('aria-live',  assertive ? 'assertive' : 'polite')
    })

    const iconEl = ui.h('span', 'ef-ui-alert-icon', { 'aria-hidden': 'true' })
    ui.bind(el, kind, function (v) { iconEl.textContent = ICONS[v] || 'ⓘ' })
    el.appendChild(iconEl)

    const inner = ui.h('div', 'ef-ui-alert-body')
    const titleEl = ui.h('div', 'ef-ui-alert-title')
    ui.bindText(titleEl, title)
    ui.bind(el, title, function (v) { titleEl.style.display = (v == null || v === '') ? 'none' : '' })
    inner.appendChild(titleEl)
    const msgEl = ui.h('div', 'ef-ui-alert-msg')
    ui.bindText(msgEl, message)
    inner.appendChild(msgEl)
    el.appendChild(inner)

    if (o.onClose) {
      const x = ui.h('button', 'ef-ui-alert-close',
        { type: 'button', text: '×', 'aria-label': 'Dismiss alert' })
      x.addEventListener('click', o.onClose)
      el.appendChild(x)
    }
    return el
  }
})(window.EF = window.EF || {})

/* ════ ui/overlay/toast.js ════ */
// EF.ui.toast — transient notification, auto-dismisses.
//
// EF.ui.toast({ kind?: 'info'|'success'|'warn'|'error', title?, message, duration? })
//   duration in ms, default 3500. Use 0 for sticky.
//
// Returns { close }. Stacks in top-right corner via a single shared stack root.
;(function (EF) {
  'use strict'
  const ui = EF.ui = EF.ui || {}

  const ICONS = { info: 'ⓘ', success: '✓', warn: '⚠', error: '⨯' }
  let stackEl = null

  function ensureStack() {
    if (stackEl && stackEl.isConnected) return stackEl
    stackEl = ui.h('div', 'ef-ui-toast-stack')
    ui.portalRoot().appendChild(stackEl)
    return stackEl
  }

  ui.toast = function (opts) {
    const o = opts || {}
    const kind = o.kind || 'info'
    const dur = o.duration == null ? 3500 : o.duration
    const stack = ensureStack()

    // ARIA: errors/warnings use role=alert (assertive) so screen readers
    // interrupt; info/success use role=status (polite).
    const assertive = kind === 'error' || kind === 'warn'
    const el = ui.h('div', 'ef-ui-toast ef-ui-toast-' + kind, {
      role:           assertive ? 'alert'     : 'status',
      'aria-live':    assertive ? 'assertive' : 'polite',
      'aria-atomic':  'true',
    })
    el.appendChild(ui.h('span', 'ef-ui-toast-icon', { text: ICONS[kind] || 'ⓘ', 'aria-hidden': 'true' }))
    const body = ui.h('div', 'ef-ui-toast-body')
    if (o.title) body.appendChild(ui.h('div', 'ef-ui-toast-title', { text: o.title }))
    body.appendChild(ui.h('div', 'ef-ui-toast-msg', { text: o.message || '' }))
    el.appendChild(body)
    const x = ui.h('button', 'ef-ui-toast-close',
      { type: 'button', text: '×', 'aria-label': 'Dismiss notification' })
    el.appendChild(x)

    stack.appendChild(el)
    requestAnimationFrame(function () { el.classList.add('ef-ui-toast-in') })

    let closed = false
    let timer = null
    function close() {
      if (closed) return
      closed = true
      if (timer) { clearTimeout(timer); timer = null }
      el.classList.remove('ef-ui-toast-in')
      el.classList.add('ef-ui-toast-out')
      setTimeout(function () {
        if (el.parentNode) el.parentNode.removeChild(el)
        if (stackEl && stackEl.children.length === 0 && stackEl.parentNode) {
          stackEl.parentNode.removeChild(stackEl)
          stackEl = null
        }
      }, 220)
    }
    x.addEventListener('click', close)
    if (dur > 0) timer = setTimeout(close, dur)
    return { el: el, close: close }
  }
})(window.EF = window.EF || {})

/* ════ ui/panel/dock-tabs.js ════ */
// Dock-tabs — the framework-side thin shell around EF.ui.tab.
//
// Zero visual code. Zero DOM construction. Its entire job is:
//   1. Pick an EF.ui.tab variant from preset defaults
//   2. Wire ctx.dock.panels → items, ctx.dock.activeId → active
//   3. Forward click / close / add / drag callbacks to ctx.dock.*
//   4. Tag the root with `.ef-dock-tabs` so interactions.js can hit-test it
//
// Registered presets (§ 4.6 — one implementation, four configurations):
//   tab-standard    closeable + addable                    (editor)
//   tab-compact     no close, hides when < 2 panels        (properties)
//   tab-collapsible closeable + click-active collapses     (utility)
//   tab-sidebar     icon-only vertical + collapsible       (left/right rail)
//
// A preset's `props` can override any of the hard-coded defaults on a
// per-toolbar-item basis — that's how a caller could, e.g., use the
// sidebar preset but force text mode with `props: { iconOnly: false }`.
;(function (EF) {
  'use strict'

  function buildDockTabs(props, ctx) {
    const p = props || {}

    const el = EF.ui.tab({
      items:        ctx.dock.panels,     // derived signal<PanelData[]>
      active:       ctx.dock.activeId,   // derived signal<string|null>
      variant:      p.variant  || 'bar',
      direction:    p.direction,
      iconOnly:     p.iconOnly,
      closable:     p.closable != null ? p.closable : true,
      addable:      !!p.addable,
      minShowCount: p.minShowCount || 0,

      onActivate: function (id) {
        ctx.dock.activatePanel(id)
        if (p.collapsible && ctx.dock.canCollapse()) ctx.dock.setCollapsed(false)
      },
      onReactivate: function () {
        // Click on already-active tab toggles dock collapse (for
        // collapsible/sidebar presets). Safe no-op otherwise.
        if (p.collapsible && ctx.dock.canCollapse()) {
          ctx.dock.setCollapsed(!ctx.dock.collapsed())
        }
      },
      onClose: function (id) {
        ctx.dock.removePanel(id)
      },
      onAdd: function () {
        // Clone the active panel's widget type (§ 4.1-ish — same as old
        // tab-add behavior). Use widgetDefaults so we don't carry state.
        const panels = ctx.dock.panels()
        const curId  = ctx.dock.activeId()
        const active = panels.find(function (pp) { return pp.id === curId })
        if (!active) return
        const defaults = EF.widgetDefaults(active.widget)
        ctx.dock.addPanel(Object.assign({}, defaults, { widget: active.widget }))
      },
      onDragStart: function (ev, panelId) {
        const fn = EF._dock && EF._dock.beginPanelDrag
        if (fn) fn(ev, panelId, ctx.dock.id(), ctx._layout)
      },
    })

    // Marker class for interactions.js hit-testing. Kept as an additional
    // class (not a replacement) so the same root still picks up all the
    // `.ef-ui-tab*` styling.
    el.classList.add('ef-dock-tabs')
    return el
  }

  function preset(defaults) {
    return function (props, ctx) {
      return buildDockTabs(Object.assign({}, defaults, props), ctx)
    }
  }

  EF.registerWidget('tab-standard', {
    defaults: function () { return { title: 'Tabs' } },
    create:   preset({ variant: 'bar', closable: true, addable: true }),
  })

  EF.registerWidget('tab-compact', {
    defaults: function () { return { title: 'Tabs' } },
    create:   preset({ variant: 'compact', closable: false, minShowCount: 2 }),
  })

  EF.registerWidget('tab-collapsible', {
    defaults: function () { return { title: 'Tabs' } },
    create:   preset({ variant: 'bar', closable: true, collapsible: true }),
  })

  EF.registerWidget('tab-sidebar', {
    defaults: function () { return { title: 'Tabs' } },
    create:   preset({
      variant:     'sidebar',
      iconOnly:    true,
      direction:   'vertical',
      closable:    false,
      collapsible: true,
    }),
  })
})(window.EF = window.EF || {})

/* ════ ui/panel/log.js ════ */
// Log panel widget — built entirely from EF.ui.* primitives.
//
// Subscribes to EF.logs and renders one ef-ui-card per entry inside a
// ef-ui-scrollarea. Click a card to dismiss. Newest on top. A segmented
// level filter (All / Error / Warn / Info / Debug) controls the visible
// subset. This is a built-in `registered panel widget` (§ 4.7) — users put
// it in any dock and they immediately see every panel error / log call /
// global throw / async rejection routed to one place.
//
// Zero custom DOM, zero custom CSS. Everything comes from the ui library.
;(function (EF) {
  'use strict'
  const ui = EF.ui

  const LEVEL_OPTS = [
    { value: 'all',   label: 'All' },
    { value: 'error', label: 'Error' },
    { value: 'warn',  label: 'Warn' },
    { value: 'info',  label: 'Info' },
    { value: 'debug', label: 'Debug' },
  ]

  function create(props, ctx) {
    const root = ui.h('div', 'ef-ui-errlog')

    // Filter bar — dropdown select on the left, spacer, copy + clear on the
    // right. Select (not segmented) keeps the toolbar compact when the log
    // panel is narrow.
    const filter = EF.signal((props && props.level) || 'all')
    const bar = ui.h('div', 'ef-ui-errlog-bar')
    bar.appendChild(ui.select({ value: filter, options: LEVEL_OPTS }))
    bar.appendChild(ui.h('div', 'ef-ui-errlog-spacer'))
    const copyBtn = ui.button({ text: 'Copy', kind: 'ghost', size: 'sm' })
    copyBtn.addEventListener('click', function () {
      const list = EF.logs()
      const lvl = filter()
      const visible = lvl === 'all' ? list : list.filter(function (e) { return e.level === lvl })
      const text = visible.map(function (e) {
        return '[' + e.level.toUpperCase() + '] ' + formatSource(e.source) + ' — ' + e.message +
          (e.stack ? '\n' + e.stack : '')
      }).join('\n')
      if (navigator.clipboard && navigator.clipboard.writeText) {
        navigator.clipboard.writeText(text).then(function () {
          ui.toast({ kind: 'success', message: 'Copied ' + visible.length + ' log entries' })
        })
      }
    })
    bar.appendChild(copyBtn)
    const clearBtn = ui.button({ text: 'Clear', kind: 'ghost', size: 'sm' })
    clearBtn.addEventListener('click', function () { EF.clearLogs() })
    bar.appendChild(clearBtn)
    root.appendChild(bar)

    const empty = ui.h('div', 'ef-ui-errlog-empty', {
      text: 'No log entries.',
    })

    const scroll = ui.scrollArea()
    root.appendChild(scroll)

    ctx.onCleanup(EF.effect(function () {
      const list = EF.logs()
      const lvl = filter()
      const visible = lvl === 'all' ? list : list.filter(function (e) { return e.level === lvl })
      scroll.replaceChildren()
      if (visible.length === 0) {
        scroll.appendChild(empty)
        return
      }
      // Newest first.
      for (let i = visible.length - 1; i >= 0; i--) {
        scroll.appendChild(buildRow(visible[i]))
      }
    }))

    return root
  }

  function buildRow(entry) {
    const lvlEl = ui.h('span', 'ef-ui-errlog-level ef-ui-errlog-level-' + entry.level, { text: entry.level.toUpperCase() })
    const srcEl = ui.h('span', 'ef-ui-errlog-src', { text: formatSource(entry.source) })
    const headRow = ui.h('div', 'ef-ui-errlog-head')
    headRow.appendChild(lvlEl); headRow.appendChild(srcEl)
    const msgEl = ui.h('div', 'ef-ui-errlog-msg', { text: entry.message })
    const children = [headRow, msgEl]
    if (entry.stack) {
      children.push(ui.h('pre', 'ef-ui-errlog-stk', { text: entry.stack }))
    }
    const card = ui.card({ padded: true, children: children })
    card.classList.add('ef-ui-errlog-row')
    card.classList.add('ef-ui-errlog-row-' + entry.level)
    card.title = 'click to dismiss'
    card.addEventListener('click', function () { EF.dismissLog(entry.id) })
    return card
  }

  function formatSource(s) {
    if (!s) return 'unknown'
    const parts = [s.scope || 'unknown']
    if (s.widget)  parts.push('widget=' + s.widget)
    if (s.dockId)  parts.push('dock=' + s.dockId)
    if (s.panelId) parts.push('panel=' + s.panelId)
    if (s.topic)   parts.push('topic=' + s.topic)
    return parts.join(' · ')
  }

  EF.registerWidget('log', {
    defaults: function () { return { title: 'Log', icon: '📋', props: { level: 'all' } } },
    create: create,
  })
})(window.EF = window.EF || {})
